import React, { useState, useEffect } from "react";
import { BrowserRouter as Router, Routes, Route, Link, useNavigate, useLocation } from "react-router-dom";
import Register from './Register';
import Home from "./Home";
import About from "./About";
import Login from "./Login";
import Profile from "./Profile";
import AdminLogin from "./admin/AdminLogin";
import AdminDashboard from "./admin/AdminDashboard";
import AdminProfile from "./admin/AdminProfile";
import ManageAdmins from "./admin/ManageAdmins"; 
import ProtectedRoute from "./admin/ProtectedRoute";

function App() {
  const [user, setUser] = useState(null);
  const [admin, setAdmin] = useState(null);

  // Sync state with localStorage on load
  useEffect(() => {
    const savedUser = localStorage.getItem('user');
    const savedAdmin = localStorage.getItem('adminUser');
    if (savedUser) setUser(JSON.parse(savedUser));
    if (savedAdmin) setAdmin(JSON.parse(savedAdmin));
  }, []);

  const handleLogout = () => {
    localStorage.clear();
    setUser(null);
    setAdmin(null);
    window.location.href = "/";
  };

  return (
    <Router>
      <nav style={navStyle}>
        <div style={navContainer}>
          <div style={leftLinks}>
            <Link to="/" style={linkStyle}>Home</Link>
            <Link to="/about" style={linkStyle}>About</Link>
          </div>

          <div style={rightLinks}>
            {!user && !admin && (
              <>
                <Link to="/login" style={linkStyle}>Citizen Login</Link>
                <Link to="/admin/login" style={adminLinkBtn}>Admin Access</Link>
              </>
            )}

            {/* Admin Profile Icon */}
            {admin && (
              <div style={profileArea}>
                {admin.role === "Super Admin" && (
                  <Link to="/admin/manage-admins" style={superAdminBadge}>👑 Manage</Link>
                )}
                <Link to="/admin/profile" style={avatarStyle}>
                  {admin.name.charAt(0).toUpperCase()}
                </Link>
                <button onClick={handleLogout} style={logoutBtn}>Logout</button>
              </div>
            )}

            {/* Citizen Profile Icon */}
            {user && !admin && (
              <div style={profileArea}>
                <Link to="/profile" style={avatarStyle}>
                  {user.name.charAt(0).toUpperCase()}
                </Link>
                <button onClick={handleLogout} style={logoutBtn}>Logout</button>
              </div>
            )}
          </div>
        </div>
      </nav>

      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/about" element={<About />} />
        <Route path="/login" element={<Login onLoginSuccess={(userData) => setUser(userData)} />} />
        <Route path="/register" element={<Register />} />
        <Route path="/profile" element={<Profile />} />

        {/* ADMIN ROUTES */}
        <Route path="/admin/login" element={<AdminLogin onAdminLogin={(adminData) => setAdmin(adminData)} />} />
        <Route path="/admin/dashboard" element={<ProtectedRoute><AdminDashboard /></ProtectedRoute>} />
        <Route path="/admin/profile" element={<ProtectedRoute><AdminProfile /></ProtectedRoute>} />
        <Route path="/admin/manage-admins" element={<ProtectedRoute><ManageAdmins /></ProtectedRoute>} />
      </Routes>
    </Router>
  );
}

// STYLING
const navStyle = { background: "#1a1a1a", padding: "15px 0", width: "100%", position: "sticky", top: 0, zIndex: 1000 };
const navContainer = { display: "flex", justifyContent: "space-between", maxWidth: "1200px", margin: "0 auto", padding: "0 20px", alignItems: "center" };
const leftLinks = { display: "flex", gap: "25px" };
const rightLinks = { display: "flex", gap: "20px", alignItems: "center" };
const linkStyle = { color: "#fff", textDecoration: "none", fontWeight: "500" };
const adminLinkBtn = { color: "#aaa", textDecoration: "none", fontSize: "14px", border: "1px solid #444", padding: "5px 10px", borderRadius: "4px" };
const profileArea = { display: "flex", alignItems: "center", gap: "15px" };
const avatarStyle = { width: "35px", height: "35px", borderRadius: "50%", background: "#764ba2", color: "white", display: "flex", alignItems: "center", justifyContent: "center", textDecoration: "none", fontWeight: "bold" };
const logoutBtn = { background: "transparent", color: "#ff4d4d", border: "none", cursor: "pointer", fontWeight: "bold" };
const superAdminBadge = { color: "#ffcc00", textDecoration: "none", fontSize: "12px", fontWeight: "bold", border: "1px solid #ffcc00", padding: "2px 8px", borderRadius: "10px" };

export default App;
